import fs from "node:fs";
import path from "node:path";

const dataDir = path.resolve("public/data");

fs.mkdirSync(dataDir, { recursive: true });

const files = {
  "enrichment-governed.json": {
    generatedAt: null,
    version: "fallback-0.1",
    items: [],
    index: {},
    bySlug: {},
    notes:
      "Fallback empty governed enrichment dataset. This file should normally be generated by the enrichment pipeline."
  },
  "source-registry.json": {
    generatedAt: null,
    version: "fallback-0.1",
    sources: [],
    index: {},
    bySlug: {},
    notes:
      "Fallback empty source registry. Replace with generated registry data when available."
  }
};

for (const [filename, content] of Object.entries(files)) {
  const filePath = path.join(dataDir, filename);

  if (!fs.existsSync(filePath)) {
    fs.writeFileSync(filePath, JSON.stringify(content, null, 2) + "\n");
    console.log(`[static-stubs] created ${filePath}`);
  } else {
    console.log(`[static-stubs] exists ${filePath}`);
  }
}
